INSERT INTO public.questions (id, exam_id, paper_id, subject_id, chapter_id, question_type, question_text, options, correct_answer, correct_answer_json, auto_gradable, source, is_active, version, source_meta, explanation)
VALUES
  ('medical-tech-moex-02288', 'medical-tech', 'medical-tech-moex-114-53d0563d', 'sub-medical-tech-06', NULL, 'single_choice', '目  前核酸萃取方式有許多種，包括管柱萃取純化法（column purification）、有機溶劑萃取純化法及磁珠萃 取純化法等，下列敘述何者最不適當？', '["管  柱萃取純化法具有操作簡單、回收率高及性能穩定的特點", "有  機溶劑萃取純化法主要以陰離子界面活性劑（SDS）將細胞打破後，進行DNA純化", "磁  珠萃取純化法是利用pH值及離子強度（strength）的不同，調控磁珠與核酸之間的吸附能力，進行DNA 純化", "有  機溶劑萃取純化法比較耗時、無法萃取完全、產量低"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:14:08+00:00", "source_pdf_sha1": "8dcf4eaf1de2", "answer_pdf_sha1": "9b103a7008ab", "source_family": "moex-gov-tw", "moex": {"exam_code": "114020", "c": "308", "s": "0502", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "醫學分子檢驗學與臨床鏡檢學（包括寄生蟲學）", "year": "114", "exam_name": "114年第一次專技人員高等考試醫師牙醫師中醫師藥師考試分階段考試、醫事檢驗師、醫事放射師、物理治療師考試", "original_question_number": 46, "answer_corrected": false, "flags": [], "slug": "mt", "db_exam_id": "medical-tech"}'::jsonb, NULL),
  ('medical-tech-moex-02289', 'medical-tech', 'medical-tech-moex-114-53d0563d', 'sub-medical-tech-06', NULL, 'single_choice', '關  於 nested PCR 與 PCR-sequence specific primer（PCR-SSP）的敘述，下列何者最不正確？', '["P CR-SSP所使用的Taq DNA聚合酶，應不具有3''端至5''端外切酶（exonuclease）活性", "n ested PCR可以降低產物的錯誤率", "臨  床上，PCR-SSP常用於多樣性基因的分型", "n ested PCR反應在執行時，需先將RNA反轉錄成cDNA"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:14:08+00:00", "source_pdf_sha1": "8dcf4eaf1de2", "answer_pdf_sha1": "9b103a7008ab", "source_family": "moex-gov-tw", "moex": {"exam_code": "114020", "c": "308", "s": "0502", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "醫學分子檢驗學與臨床鏡檢學（包括寄生蟲學）", "year": "114", "exam_name": "114年第一次專技人員高等考試醫師牙醫師中醫師藥師考試分階段考試、醫事檢驗師、醫事放射師、物理治療師考試", "original_question_number": 47, "answer_corrected": false, "flags": [], "slug": "mt", "db_exam_id": "medical-tech"}'::jsonb, NULL),
  ('medical-tech-moex-02290', 'medical-tech', 'medical-tech-moex-114-53d0563d', 'sub-medical-tech-06', NULL, 'single_choice', '關  於限制性片段長度多型性（restriction fragment length polymorphism, RFLP）的敘述，下列何者最不 正確？', '["無  法運用在基因甲基化位點的分析", "利  用限制酶能夠辨識雙股DNA的特定序列來做分析", "可  用南方點墨法（Southern blot hybridization）分析", "可  用於執行親子鑑定"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:14:08+00:00", "source_pdf_sha1": "8dcf4eaf1de2", "answer_pdf_sha1": "9b103a7008ab", "source_family": "moex-gov-tw", "moex": {"exam_code": "114020", "c": "308", "s": "0502", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "醫學分子檢驗學與臨床鏡檢學（包括寄生蟲學）", "year": "114", "exam_name": "114年第一次專技人員高等考試醫師牙醫師中醫師藥師考試分階段考試、醫事檢驗師、醫事放射師、物理治療師考試", "original_question_number": 48, "answer_corrected": false, "flags": [], "slug": "mt", "db_exam_id": "medical-tech"}'::jsonb, NULL),
  ('medical-tech-moex-02291', 'medical-tech', 'medical-tech-moex-114-53d0563d', 'sub-medical-tech-06', NULL, 'single_choice', '下  列何種生物晶片最適合用於檢測大量已知SNP？', '["微  陣列比較型基因組雜交（aCGH）", "互  補DNA微陣列（cDNA microarray）", "寡  核苷酸微陣列（oligonucleotide microarray）", "晶  片實驗室（lab-on-a-chip）"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:14:08+00:00", "source_pdf_sha1": "8dcf4eaf1de2", "answer_pdf_sha1": "9b103a7008ab", "source_family": "moex-gov-tw", "moex": {"exam_code": "114020", "c": "308", "s": "0502", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "醫學分子檢驗學與臨床鏡檢學（包括寄生蟲學）", "year": "114", "exam_name": "114年第一次專技人員高等考試醫師牙醫師中醫師藥師考試分階段考試、醫事檢驗師、醫事放射師、物理治療師考試", "original_question_number": 49, "answer_corrected": false, "flags": [], "slug": "mt", "db_exam_id": "medical-tech"}'::jsonb, NULL),
  ('medical-tech-moex-02292', 'medical-tech', 'medical-tech-moex-114-53d0563d', 'sub-medical-tech-06', NULL, 'single_choice', '在  人類基因體中，針對單一核苷酸多型性（SNP）的敘述，下列何者最不適當？', '["S NP可視為生物標幟（biomarker），用來了解與特定疾病的相關性", "S NP是指位於基因編碼區（coding region）中的變異", "S NP並不一定會造成顯著的基因表現型（phenotype）差異", "有  些SNP與藥物治療反應有關，可作為個人化醫療（personalized medicine）的評估"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:14:08+00:00", "source_pdf_sha1": "8dcf4eaf1de2", "answer_pdf_sha1": "9b103a7008ab", "source_family": "moex-gov-tw", "moex": {"exam_code": "114020", "c": "308", "s": "0502", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "醫學分子檢驗學與臨床鏡檢學（包括寄生蟲學）", "year": "114", "exam_name": "114年第一次專技人員高等考試醫師牙醫師中醫師藥師考試分階段考試、醫事檢驗師、醫事放射師、物理治療師考試", "original_question_number": 50, "answer_corrected": false, "flags": [], "slug": "mt", "db_exam_id": "medical-tech"}'::jsonb, NULL),
  ('medical-tech-moex-02293', 'medical-tech', 'medical-tech-moex-114-53d0563d', 'sub-medical-tech-06', NULL, 'single_choice', '美  國分子病理學會（Association for Molecular Pathology, AMP）在2017年公布"巨量平行定序（massive parallel sequencing）"在臨床應用的守則，讓臨床工作人員因此有所依據，該守則中沒有針對下列那一項 進行規範？', '["定  序深度", "定  序品質", "分  析流程", "機  台種類"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:14:08+00:00", "source_pdf_sha1": "8dcf4eaf1de2", "answer_pdf_sha1": "9b103a7008ab", "source_family": "moex-gov-tw", "moex": {"exam_code": "114020", "c": "308", "s": "0502", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "醫學分子檢驗學與臨床鏡檢學（包括寄生蟲學）", "year": "114", "exam_name": "114年第一次專技人員高等考試醫師牙醫師中醫師藥師考試分階段考試、醫事檢驗師、醫事放射師、物理治療師考試", "original_question_number": 51, "answer_corrected": false, "flags": [], "slug": "mt", "db_exam_id": "medical-tech"}'::jsonb, NULL),
  ('medical-tech-moex-02294', 'medical-tech', 'medical-tech-moex-114-53d0563d', 'sub-medical-tech-06', NULL, 'single_choice', '關  於chemical cleavage of mismatch duplexes（CCM）技術，下列敘述何者最正確？', '["用  來偵測基因內多個鹼基突變", "反  應中之hydroxylamine修飾配對錯誤鹼基中的胸腺嘧啶（thymine）", "反  應中的piperidine針對修飾後的胞嘧啶（cytosine）及胸腺嘧啶（thymine）位置進行切割", "僅  適用於短的（小於1 kb）DNA片段分析"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:14:08+00:00", "source_pdf_sha1": "8dcf4eaf1de2", "answer_pdf_sha1": "9b103a7008ab", "source_family": "moex-gov-tw", "moex": {"exam_code": "114020", "c": "308", "s": "0502", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "醫學分子檢驗學與臨床鏡檢學（包括寄生蟲學）", "year": "114", "exam_name": "114年第一次專技人員高等考試醫師牙醫師中醫師藥師考試分階段考試、醫事檢驗師、醫事放射師、物理治療師考試", "original_question_number": 52, "answer_corrected": false, "flags": [], "slug": "mt", "db_exam_id": "medical-tech"}'::jsonb, NULL),
  ('medical-tech-moex-02295', 'medical-tech', 'medical-tech-moex-114-53d0563d', 'sub-medical-tech-06', NULL, 'single_choice', '探  針雜合反應廣泛運用在核酸分子檢測，下列敘述何者最不適當？', '["探  針的長度可決定偵測的特異性", "雜  合反應溶液的鹽類濃度越高，偵測特異性越高", "進  行南方墨點法時，使用RNA探針比DNA探針偵測靈敏度更高", "p eptide nucleic acid（PNA）探針的骨架減少了負電荷，因此結合至標的基因會更有效率"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:14:08+00:00", "source_pdf_sha1": "8dcf4eaf1de2", "answer_pdf_sha1": "9b103a7008ab", "source_family": "moex-gov-tw", "moex": {"exam_code": "114020", "c": "308", "s": "0502", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "醫學分子檢驗學與臨床鏡檢學（包括寄生蟲學）", "year": "114", "exam_name": "114年第一次專技人員高等考試醫師牙醫師中醫師藥師考試分階段考試、醫事檢驗師、醫事放射師、物理治療師考試", "original_question_number": 53, "answer_corrected": false, "flags": [], "slug": "mt", "db_exam_id": "medical-tech"}'::jsonb, NULL),
  ('medical-tech-moex-02296', 'medical-tech', 'medical-tech-moex-114-53d0563d', 'sub-medical-tech-06', NULL, 'single_choice', '下  列何者方法最適合鑑定未知細菌抗藥性基因的變異？', '["全  轉錄組定序（whole transcriptome sequencing）", "全  外顯子定序（whole exome sequencing）", "全  基因組定序（whole genome sequencing）", "標  的基因定序（targeted sequencing）"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:14:08+00:00", "source_pdf_sha1": "8dcf4eaf1de2", "answer_pdf_sha1": "9b103a7008ab", "source_family": "moex-gov-tw", "moex": {"exam_code": "114020", "c": "308", "s": "0502", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "醫學分子檢驗學與臨床鏡檢學（包括寄生蟲學）", "year": "114", "exam_name": "114年第一次專技人員高等考試醫師牙醫師中醫師藥師考試分階段考試、醫事檢驗師、醫事放射師、物理治療師考試", "original_question_number": 54, "answer_corrected": false, "flags": [], "slug": "mt", "db_exam_id": "medical-tech"}'::jsonb, NULL),
  ('medical-tech-moex-02297', 'medical-tech', 'medical-tech-moex-114-53d0563d', 'sub-medical-tech-06', NULL, 'single_choice', '關  於可逆性中斷子定序法（reversible terminator-based sequencing）的敘述，下列何者最正確？', '["正  確配對的中斷子（terminator）不會發出螢光", "可  逆性中斷子（reversible terminator）為雙去氧核苷酸（dideoxynucleotide）", "加  入酸性溶液後，才可以繼續下一個鹼基的定序", "此  法是運用乳化式增幅（emulsion amplification）原理"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:14:08+00:00", "source_pdf_sha1": "8dcf4eaf1de2", "answer_pdf_sha1": "9b103a7008ab", "source_family": "moex-gov-tw", "moex": {"exam_code": "114020", "c": "308", "s": "0502", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "醫學分子檢驗學與臨床鏡檢學（包括寄生蟲學）", "year": "114", "exam_name": "114年第一次專技人員高等考試醫師牙醫師中醫師藥師考試分階段考試、醫事檢驗師、醫事放射師、物理治療師考試", "original_question_number": 55, "answer_corrected": false, "flags": [], "slug": "mt", "db_exam_id": "medical-tech"}'::jsonb, NULL)
